INSERT INTO `announcements` (`id`, `title`, `content_html`, `created_by`, `created_at`, `updated_at`) VALUES
(1, 'Urgent Banget', '<p><strong><em>halooo gaess</em></strong><br><br><strong><em>tolong segera ditindaklanjuti yaaa</em></strong><br><br><strong><em>terima kasih</em></strong><br><br><a target=\"_blank\" href=\"https://idnsolo.com\" rel=\"noreferrer noopener\">kabar kabar kalo sudah......</a><br><br></p>', 13, '2026-03-04 06:42:53', '2026-03-04 06:42:53'),
(2, 'hmmmmmm', '<ol><li><p><strong>adaasad</strong></p></li><li><p><strong>adsas</strong></p></li><li><p><strong>ad</strong></p></li><li><p><strong>a</strong><br></p></li></ol>', 13, '2026-03-04 06:54:58', '2026-03-04 06:54:58'),
(3, '23r4t56', '<img src=\"data:image/webp;base64,\" alt=\"announcement-image\">', 13, '2026-03-04 06:56:33', '2026-03-04 06:56:33'),
(4, 'asdfasfas', '<p>dfasfasfda</p><p>dsafafas</p><p>asdf</p><p>sad</p><p>a</p><p>d</p><p>af</p><img src=\"data:image/webp;base64,\" alt=\"announcement-image\"><p></p>', 13, '2026-03-04 06:59:34', '2026-03-04 06:59:34');
INSERT INTO `announcements` (`id`, `title`, `content_html`, `created_by`, `created_at`, `updated_at`) VALUES
(5, 'qerq', '<p>eqqe</p><p>qwewqe</p><p><em>qeqwewq</em></p><p><em><u>3243243243</u></em></p><ul><li><p>sadkjadslfkj</p></li><li><p>afsjdkdsaj</p></li><li><p>afsjksadf</p></li></ul><p></p><img src=\"data:image/webp;base64,\" alt=\"announcement-image\"><p>dfjdafs</p><p></p><ol><li><p>asfdafa</p></li><li><p>asdfasf</p></li><li><p>afsd</p></li><li><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://idnsolo.com\">dsfadafs</a></p></li></ol><p></p>', 13, '2026-03-05 03:32:59', '2026-03-05 03:32:59'),
(6, 'penguman pengumuman', '<img src=\"data:image/webp;base64,\" alt=\"announcement-image\"><ol><li><p>Halo gaes</p></li><li><p>Dimohon segera melakukan input data kemarin yaa</p></li><li><p>Ditunggu segera, karena untuk sinkronisasi data</p></li></ol><p></p><p>Thanks.</p><p></p>', 13, '2026-03-05 05:42:56', '2026-03-05 05:42:56');
INSERT INTO `announcements` (`id`, `title`, `content_html`, `created_by`, `created_at`, `updated_at`) VALUES
(7, 'Segera Kembali', '<p>Stock di werehouse sudah bisa di ambil, sebelum pukul 17.00 WIB diharapkan sudah tiba disana. Terima kasih.<br></p><img src=\"data:image/webp;base64,\" alt=\"announcement-image\"><blockquote><p><strong><em>UJI COBA BAGIAN LAIN</em></strong></p></blockquote><ol><li><p>adsadd</p></li><li><p>dasad</p></li><li><p>asd</p></li><li><p>adsdsd</p></li></ol><p></p>', 13, '2026-03-07 08:48:47', '2026-03-07 08:48:47'),
(8, 'Sudah bisa kembali ke Werehouse', '<h2>Segera kembali yah gaess...</h2><ol><li><p>Soalnya sudah ditunggu stockist lain</p></li><li><p>Agar bisa melakukan supply ke pelanggan dan memenuhi target harian</p></li></ol><p>Terima kasih....<br><br></p><img src=\"data:image/webp;base64,\" alt=\"announcement-image\"><p></p>', 13, '2026-03-07 09:05:24', '2026-03-07 09:05:24');
